-- 1. Driveway Installers x Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'driveway-installers',
  'web-design',
  'Driveway installation is one of the most visual trades in existence, yet the majority of driveway contractors in Kent rely on websites that fail to showcase their craftsmanship. Homeowners considering a new block paving, resin bound, or tarmac driveway are making a decision worth thousands of pounds, and they need to see proof of quality before they will even pick up the phone. A purpose-built driveway installer website needs before-and-after project galleries with high-resolution imagery of completed block paving patterns, resin bound colour blends, and tarmac finishes. It needs material comparison tools that let visitors explore the differences between Marshalls block paving and Ronacrete resin bound systems, alongside an instant quote calculator that captures driveway dimensions, preferred materials, and access details around the clock. Most driveway company websites are little more than a logo, a phone number, and a few blurry phone photos taken mid-pour. We build websites that transform your completed driveways into a visual sales engine, letting homeowners compare herringbone versus stretcher bond patterns, explore colour palettes for resin bound aggregate blends, and request a quote without waiting for Monday morning.',
  'Homeowners researching driveway replacements spend days comparing contractors online before making contact. They scrutinise project photos, compare block paving patterns against resin bound finishes, and check whether you handle SuDS-compliant drainage solutions for impermeable surfaces. A website that merely lists your services without showcasing finished driveways in different materials, explaining permeable paving regulations, or offering transparent pricing guidance loses these high-value prospects to competitors who present their portfolio more professionally.',
  'We photograph or source high-quality imagery of your completed driveways and build interactive before-and-after sliders showing cracked concrete transformed into herringbone block paving or oil-stained tarmac replaced with golden resin bound. Material showcase pages compare block paving, resin bound, tarmac, and Indian sandstone with honest maintenance requirements and realistic pricing bands.',
  '[{"title": "Poor-quality project photos failing to convert visitors", "description": "Most driveway installer websites feature a handful of low-resolution photos taken mid-job with cement dust still settling. Homeowners comparing contractors side by side will gravitate toward the company whose portfolio shows completed block paving with freshly jointed patterns, clean resin bound edges against granite kerbing, and tarmac driveways with crisp apron detailing, regardless of who does the better work on site."}, {"title": "No material comparison tools for undecided homeowners", "description": "Visitors arrive knowing they want a new driveway but unsure whether block paving at sixty pounds per square metre, resin bound at seventy-five, or tarmac at forty-five suits their property and budget. Without interactive comparison tools showing real installed examples of each material alongside maintenance requirements and expected lifespans, these undecided prospects leave your site to research elsewhere and rarely return."}, {"title": "Zero lead capture outside of working hours", "description": "Most driveway enquiries come from homeowners browsing in the evening after work. Without an instant quote calculator that captures driveway dimensions, preferred material type, current surface condition, and vehicle access width, you lose these evening prospects to the competitor whose site collects their details and sends an automated acknowledgement while your phone is off."}]',
  '[{"title": "Before-and-after project galleries with material filtering", "description": "We build filterable galleries organised by material type: block paving in herringbone, basket weave, and stretcher bond; resin bound in natural stone, recycled glass, and bespoke colour blends; tarmac with decorative borders; and Indian sandstone in buff, grey, and autumn tones. Interactive before-and-after sliders let visitors drag across transformations from cracked concrete to immaculate block paving."}, {"title": "Material showcase pages with honest cost comparisons", "description": "Dedicated pages for block paving, resin bound, tarmac, Indian sandstone, and gravel driveways featuring real installed photography from your projects, per-square-metre pricing guidance, maintenance schedules including resin bound power washing and block paving re-sanding, and lifespan expectations. These pages capture homeowners researching specific materials and position you as the knowledgeable local authority."}, {"title": "Integrated instant quote calculator", "description": "A step-by-step calculator that captures driveway dimensions with a visual area estimator, chosen material from a photo-based selection menu, access width for skip and machinery delivery, existing surface removal requirements, and drainage needs for impermeable surfaces. Homeowners receive an indicative price range immediately while you receive a fully qualified lead."}]',
  '[{"question": "Can you build a website that shows my driveways in their best light?", "answer": "We either work with your existing project photos and professionally edit them for colour accuracy and composition, or we arrange photography of your best completed driveways including overhead drone shots that show full pattern layouts for block paving and colour distribution for resin bound surfaces. Every image is optimised for fast loading without sacrificing the detail that sells your craftsmanship."}, {"question": "How does the instant quote calculator work?", "answer": "Visitors enter their approximate driveway dimensions using a visual area tool, select their preferred material from a photo-based menu showing your actual installed examples, and answer questions about existing surface removal, drainage requirements, and vehicle access width. The calculator provides an indicative price range based on your rates while sending you a structured lead with enough detail to follow up with an accurate quote."}, {"question": "Will my website rank for driveway searches in my area?", "answer": "Every site we build includes foundational SEO with material-specific pages targeting searches like resin bound driveway installers near me and block paving contractors in your target town, proper schema markup for local trades, and Google Business Profile integration. This provides a strong ranking foundation that a dedicated SEO campaign can build upon."}, {"question": "How long does a driveway installer website take to build?", "answer": "Most driveway company websites launch within four to six weeks. The timeline depends primarily on project photography. If you have strong existing images of completed block paving, resin bound, and tarmac projects we can move quickly. If we need to photograph recently completed driveways, we schedule shoots around your project pipeline to capture the best examples."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Driveway Installers x SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'driveway-installers',
  'seo',
  'When a homeowner in Kent types block paving driveway near me or resin bound installer into Google, the contractors appearing in the top three map pack results capture the overwhelming majority of enquiries. Driveway installation is a high-value, low-frequency purchase, meaning homeowners research extensively but ultimately contact only two or three companies for quotes. If your business is buried on page two or invisible in the Google Map Pack, those five-thousand-pound to fifteen-thousand-pound projects go to competitors by default. The challenge for driveway installers is that national directories like Checkatrade, Bark, and MyBuilder aggressively target material-specific keywords like resin bound driveway cost and block paving patterns, pushing genuine local contractors down the rankings. Our SEO campaigns are built specifically for the driveway installation industry, targeting material-specific search terms that homeowners use when comparing block paving versus resin bound, location-based queries across every Kent town you serve, and the long-tail cost and maintenance questions that signal genuine buying intent.',
  'Driveway projects typically range from three thousand to fifteen thousand pounds, making every organic lead extremely valuable. Homeowners do not impulse-buy driveways. They search for resin bound driveway cost per square metre, compare block paving patterns for front gardens, and read about permeable paving drainage requirements. If your website does not appear for these specific material and cost queries, you are invisible at the exact moment they are shortlisting contractors to invite for site surveys.',
  'We build content around the specific materials you install: dedicated optimised pages for block paving patterns and costs, resin bound colour options and SuDS compliance, tarmac durability and pricing, and Indian sandstone maintenance. Each page targets the exact search terms homeowners use including cost queries and material comparisons. Location pages cover every town in your service area with genuine local project references.',
  '[{"title": "National directories dominating your local driveway searches", "description": "Checkatrade, Bark, MyBuilder, and Rated People invest millions in SEO to rank for searches like block paving installers near me and resin bound driveway companies. Without a deliberate strategy to outrank these platforms, your website sits beneath multiple directory listings where you are one name among dozens, stripped of the before-and-after galleries and material expertise that differentiate you from every other listed contractor."}, {"title": "No visibility for material-specific searches", "description": "Homeowners who have decided on resin bound search for resin bound driveway cost per square metre and resin bound colours. Those wanting block paving search for herringbone block paving front garden and Marshalls block paving prices. Most driveway websites have a single services page listing everything, meaning they rank for nothing specifically and miss the most qualified, ready-to-buy traffic."}, {"title": "Seasonal search peaks going uncaptured", "description": "Driveway searches spike dramatically in March through May and again in September as homeowners want work completed before summer entertaining or winter weather. Companies without established SEO presence cannot capitalise on these seasonal surges because rankings take months to build. By the time you react to spring demand, the peak enquiry window has passed."}]',
  '[{"title": "Material-specific landing pages targeting buyer searches", "description": "We create in-depth, optimised pages for every material you install, targeting searches like resin bound driveway cost per square metre, herringbone block paving patterns, and tarmac driveway pros and cons. Each page features your own installed project photography, honest pricing guidance, maintenance schedules, and lifespan expectations. These pages attract homeowners who have decided on their material and are actively seeking a local installer."}, {"title": "Hyper-local pages covering your full service area", "description": "Individual location pages for every town and village you serve, featuring genuine project references from each area where possible. Block paving driveways Maidstone, resin bound installers Tonbridge, tarmac driveway contractors Ashford: each material-plus-location combination captures specific local searches and positions you as the established choice in that area."}, {"title": "Google Business Profile optimisation for Map Pack dominance", "description": "We optimise your profile with driveway-specific service categories, geotagged before-and-after project photos showing material transformations, structured review generation prompts sent after project completion, and regular Google Posts showcasing recent block paving patterns, resin bound colour blends, and completed driveway transformations across Kent."}]',
  '[{"question": "How long before I start getting driveway enquiries from SEO?", "answer": "Most driveway installers see measurable ranking improvements within eight to twelve weeks for specific material and location terms like resin bound driveways Sevenoaks. Broader competitive terms like driveway installer near me typically require four to six months. We prioritise high-intent material-specific keywords first because a homeowner searching for block paving cost per square metre is further along in their decision than someone searching driveway ideas."}, {"question": "Can you help me rank for resin bound driveway searches specifically?", "answer": "Resin bound is one of the highest-value keyword clusters in the driveway industry. We build comprehensive content covering resin bound costs per square metre, colour and aggregate options, UV stability and maintenance, SuDS compliance for planning applications, and comparisons against block paving and tarmac. This captures homeowners at every research stage from initial curiosity through to contractor shortlisting."}, {"question": "Do I need a blog to rank for driveway keywords?", "answer": "Regular project case studies outperform generic blog posts for driveway contractors. Publishing detailed write-ups of completed installations, including the client brief, material selection rationale, drainage solutions implemented, and finished photography, builds topical authority while providing genuinely useful content. We create a realistic publishing schedule tied to your project completions rather than demanding weekly articles."}, {"question": "What if I only cover a few towns rather than all of Kent?", "answer": "We tailor your campaign to your actual service radius. If you primarily work within fifteen miles of your base, we concentrate all SEO effort on those specific towns and postcodes. Focused local authority in a concentrated area delivers faster and stronger results than spreading content thinly across an entire county."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
