-- 3. Driveway Installers x Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'driveway-installers',
  'lead-capture',
  'A single driveway installation can be worth five thousand to fifteen thousand pounds in revenue, yet most driveway contractors rely on a phone number and a generic contact form to capture enquiries. When a homeowner visits your website at nine in the evening after comparing three block paving contractors, they need a way to engage immediately or they move on to the next search result. Traditional contact forms that ask for a name, email, and message give you almost nothing to work with and make the homeowner feel like they are shouting into a void with no idea when or whether you will respond. Purpose-built lead capture for driveway installers means multi-step quote forms that walk homeowners through their project: capturing driveway dimensions with a visual area estimator, material preferences with photo-based selection between block paving patterns and resin bound colour blends, current surface condition, skip access width, and photos of their existing drive. This structured approach qualifies every lead before it reaches your inbox and gives the homeowner confidence that you will respond with a relevant, material-specific quote rather than a generic callback.',
  'Driveway projects have long consideration periods. Homeowners compare block paving against resin bound, research costs per square metre, consider permeable paving for planning compliance, and shortlist contractors over several weeks. When they finally decide to reach out, the window is narrow. If your site offers nothing beyond a phone number and a basic form, evening and weekend browsers who represent the majority of your traffic cannot engage meaningfully and enquire with whichever competitor makes the process easiest.',
  'Our lead capture forms mirror the driveway quoting process. Multi-step flows ask for property type, current driveway surface, desired material with visual selectors showing herringbone block paving versus natural resin bound, approximate dimensions, vehicle count, skip access width, and drainage requirements. Photo upload fields let homeowners show their cracked concrete or oil-stained tarmac. Every submission arrives as a qualified brief you can price immediately.',
  '[{"title": "Evening and weekend visitors leaving without enquiring", "description": "The majority of homeowners browse driveway websites outside business hours, comparing block paving galleries on one site against resin bound portfolios on another. With only a phone number and a basic contact form, these visitors cannot meaningfully engage with your business. They bookmark your site, forget about it, and ultimately enquire with whichever contractor they find first when they search again."}, {"title": "Unqualified enquiries wasting site visit time", "description": "Generic contact forms generate vague messages like I want a new driveway, please call me. You spend fifteen minutes on the phone asking whether they want block paving or resin bound, what their approximate driveway area is, and whether a skip lorry can access their property. You then drive thirty minutes to a site visit only to discover the driveway is too small for your minimum project value or the access is impossible for machinery."}, {"title": "No follow-up system for prospects comparing materials", "description": "Many homeowners request information about both block paving and resin bound before deciding which material to pursue. Without an automated follow-up sequence that sends material comparison guides, cost breakdowns, and maintenance information, these undecided prospects drift to competitors who nurture them through the decision process."}]',
  '[{"title": "Multi-step driveway quote calculator with visual material selection", "description": "A guided form walks homeowners through material selection using photo tiles of your actual installed block paving, resin bound, tarmac, and stone driveways. They enter dimensions using a visual area tool with measurement guidance, specify vehicle count and access width, note any drainage or gradient concerns, and upload photos of their current driveway. Every submission arrives as a structured brief with enough detail to provide an accurate indicative quote."}, {"title": "Automated lead qualification and priority scoring", "description": "Each enquiry is automatically scored based on driveway area, chosen material value, project timeline, and postcode proximity. A homeowner wanting a large resin bound driveway within six weeks in your core service area is flagged for immediate follow-up. A smaller tarmac enquiry with a vague timeline enters an appropriate nurture sequence. Your time goes to the leads most likely to convert into high-value projects."}, {"title": "Material decision nurture sequences", "description": "Homeowners who use the quote calculator but have not committed to a material receive a targeted email sequence: a block paving versus resin bound comparison guide featuring your projects, a cost breakdown showing price per square metre for each material, maintenance requirement comparisons, and customer testimonials from homeowners who chose each option. This nurturing converts undecided browsers into committed prospects."}]',
  '[{"question": "Will a quote calculator replace the need for site visits?", "answer": "No, it complements them. The calculator captures enough detail including driveway dimensions, material preference, current surface condition, access width, and photos to provide an indicative price range and qualify the lead. You still conduct site visits to deliver accurate quotes, but every visit is now with a homeowner who has already confirmed their material preference, budget expectations, and that their property is suitable for your work."}, {"question": "What information does the lead capture form collect?", "answer": "The form collects property type, current driveway surface condition, desired material using visual photo selection, approximate dimensions via an interactive area tool, number of vehicles to accommodate, skip and machinery access width, drainage requirements for impermeable surfaces, desired project timeline, and optional photos of the existing driveway. This gives you everything needed to provide an informed initial response."}, {"question": "Can leads go directly into my existing CRM or quoting software?", "answer": "Yes. We integrate lead capture forms with most popular CRM systems and can set up direct email notifications with the full project brief, SMS alerts for high-priority large driveway leads, and automatic data entry into your preferred quoting or project management tools. Leads can also trigger automated acknowledgement messages so homeowners know their enquiry has been received."}, {"question": "How do the follow-up email sequences work?", "answer": "When a homeowner completes the quote calculator but does not immediately book a site visit, they receive a sequence of emails over the following weeks featuring completed driveway galleries in their chosen material, genuine customer reviews from similar projects, a maintenance guide for their selected surface, and a prompt to book a free site survey. Each email reinforces your expertise with that specific material."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
