-- 6. Driveway Installers x Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'driveway-installers',
  'social-media-setup',
  'Driveway installation is inherently visual and transformative, making it one of the most naturally engaging trades on social media. A cracked, oil-stained concrete slab transformed into a pristine herringbone block paving driveway is the kind of before-and-after content that stops people mid-scroll on Facebook and Instagram. Yet most driveway contractors either have no social media presence or post sporadically with low-quality photos and no strategy. A properly set up social media presence for a driveway installer turns every completed project into a content asset that generates enquiries from homeowners who see their neighbour''s tired driveway reflected in your before photos and your beautiful finished work as the solution. We set up and optimise your Facebook and Instagram profiles specifically for the driveway industry, create content templates for before-and-after project reveals, time-lapse installation videos, material showcase posts, and customer testimonial features, and establish a posting rhythm that maintains visibility without requiring you to spend evenings creating content after a long day on the tools.',
  'Social proof is everything in the driveway industry. Homeowners making a five-thousand-pound decision want to see recent completed work, not just a static website gallery. Social media provides a living portfolio that shows your latest projects, demonstrates your consistency, and lets potential customers see genuine reactions from satisfied homeowners. Contractors with active, well-presented social profiles receive more enquiries and close at higher rates because the trust is already established before the site survey.',
  'We set up your profiles with industry-specific optimisation: cover images showcasing your best driveway transformation, bio text targeting local driveway searches, highlight categories for each material type, and pinned posts featuring your strongest before-and-after projects. Content templates make it simple for you to photograph a completed block paving driveway and produce a professional post in minutes.',
  '[{"title": "No consistent social media presence despite visual work", "description": "Driveway installation produces some of the most dramatic before-and-after transformations in any trade, yet most contractors post nothing or share occasional blurry photos with no context. Meanwhile, competitors with consistent, well-photographed social feeds build followings of local homeowners who contact them directly when they are ready for a new driveway, bypassing Google search entirely."}, {"title": "Inability to showcase different materials and patterns effectively", "description": "Your social feed should function as a living catalogue showing the range of materials and patterns you install: herringbone and basket weave block paving, natural stone and recycled glass resin bound, decorative tarmac borders, Indian sandstone patios connecting to driveways. Without structured content categories, your feed is a jumble that fails to demonstrate your full capability to prospective customers."}, {"title": "No system for capturing project content during installations", "description": "By the time you finish a driveway, clean up, and load the van, the last thing you want to do is stage photos. Without a simple system for capturing before shots when you arrive, progress shots during excavation and sub-base work, and finished photos once the driveway is complete, your best marketing content drives away with the skip lorry."}]',
  '[{"title": "Profile optimisation for local driveway searches", "description": "We configure your Facebook and Instagram profiles as local search assets: business category set to driveway contractor, location and service area clearly defined, bio text incorporating key terms like block paving, resin bound, and your Kent service area. Cover images showcase your most impressive transformation. Highlight reels are organised by material type so homeowners can browse your block paving, resin bound, and tarmac portfolios separately."}, {"title": "Before-and-after content templates and posting system", "description": "We create branded content templates for your most common post types: dramatic before-and-after reveals with swipe or slider formats, completed project showcases with material and pattern details, time-lapse installation videos, and customer testimonial features. A simple capture guide helps your crew photograph each project stage so content creation takes minutes rather than hours."}, {"title": "Material showcase and seasonal content calendar", "description": "A structured content calendar ensures regular posts covering each material type, seasonal timing advice for homeowners considering new driveways, maintenance tips for existing surfaces, and behind-the-scenes installation process content. This positions you as the knowledgeable local driveway authority and keeps your profiles active through both peak and quieter periods."}]',
  '[{"question": "Which social media platforms work best for driveway installers?", "answer": "Facebook and Instagram deliver the strongest results for driveway contractors. Facebook reaches the homeowner demographic most likely to invest in a new driveway and supports local community group engagement. Instagram is ideal for visual before-and-after content and material showcasing. We set up both platforms optimised for your specific service area and material specialisms."}, {"question": "How do I create content when I am on site all day?", "answer": "We design a minimal-effort capture system. Your crew takes a before photo on arrival, one or two progress shots during key stages like excavation and sub-base laying, and a series of finished photos once the driveway is complete. These feed into branded templates that produce professional posts in minutes. The heavy creative work is done upfront in the templates, not repeated for every project."}, {"question": "Can social media actually generate driveway leads?", "answer": "Consistently. Driveway before-and-after posts are among the highest-engagement content in local trade social media. Homeowners who see a neighbour''s street or a similar property style in your posts contact you directly. Social media also validates your business when homeowners find you through Google and check your profiles for recent work and customer interactions before making contact."}, {"question": "How often should a driveway installer post on social media?", "answer": "Two to three posts per week is optimal for maintaining visibility without creating an unsustainable content burden. During busy seasons when you are completing multiple driveways weekly, content is abundant. During quieter periods, we fill gaps with material guides, maintenance tips, throwback projects, and seasonal planning content that keeps your profiles active and engaging."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
